<!-- 正品 -->
<template>  <div :class="className">    <div v-for="(item, index) in items" :key="index" :class="itemClass">      <div :class="imageClass" :style="{ backgroundImage: `url(${item.imageUrl})` }"></div>      <span>{{ item.title }}</span>      <div :class="textTipsClass">        <span>{{ item.price }}</span>        <span>{{ item.sales }}</span>      </div>    </div>  </div></template><script lang="ts">import { defineComponent, PropType } from '@vue/composition-api';interface Item {  imageUrl: string;  title: string;  price: string;  sales: string;}export default defineComponent({  name: 'NationalStandard',  props: {    className: {      type: String,      default: 'hezipail'    },    itemClass: {      type: String,      default: 'kkkkil'    },    imageClass: {      type: String,      default: 'images'    },    textTipsClass: {      type: String,      default: 'textTips'    },    items: {          type: Array as PropType<Item[]>,          default: () => []        }  }});</script><style lang="scss" scoped>.hezipail {  display: flex;  flex-wrap: wrap;  justify-content: space-between;  margin-left: -1%;  margin-right: -1%;}.images {  background-color: skyblue;  width: 100%;  height: 150px;  background-size: cover;  background-position: center;  border-radius: 8px;  margin-bottom: 10px;}.kkkkil {  display: flex;  flex-direction: column;  justify-content: center;  align-items: center;  width: 48%;  margin-bottom: 20px;}.textTips {  display: flex;  justify-content: space-between;  align-items: center;  width: 100%;  margin-top: 10px;  span {    color: #FD3905;    font-weight: 600;  }  span + span {    color: #9D9D9D;    font-size: 10px;  }}</style>